+#[test]
+fn check_succeeds_without_global() {
+    FaultInjector::reset_global();
+    // When no global injector is set, check should succeed (no fault configured)
+    let result = FaultInjector::check(FaultPoint::DbWrite);
+    assert!(result.is_ok());
+}
